  "inlineSchema": "// ==============================================\n// Ethiopian Orthodox Mezmur Platform\n// Prisma Schema — Neon DB (Serverless Postgres)\n// ==============================================\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../app/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Role {\n  USER\n  EDITOR\n  SUPER_ADMIN\n}\n\n// ==============================================\n// Better Auth Models\n// These models are required by Better Auth's\n// Prisma adapter. Do not rename the fields.\n// ==============================================\n\nmodel User {\n  id            String   @id @default(cuid())\n  name          String\n  email         String   @unique\n  emailVerified Boolean  @default(false)\n  image         String?\n  role          Role     @default(USER)\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  sessions      Session[]\n  accounts      Account[]\n  favorites     Favorite[]\n  ratings       Rating[]\n  listenHistory ListenHistory[]\n  auditLogs     AuditLog[]      @relation(\"UserAuditLogs\")\n\n  @@map(\"users\")\n}\n\nmodel Session {\n  id        String   @id @default(cuid())\n  expiresAt DateTime\n  token     String   @unique\n  ipAddress String?\n  userAgent String?\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"sessions\")\n}\n\nmodel Account {\n  id                    String    @id @default(cuid())\n  accountId             String\n  providerId            String\n  userId                String\n  user                  User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  accessToken           String?\n  refreshToken          String?\n  idToken               String?\n  accessTokenExpiresAt  DateTime?\n  refreshTokenExpiresAt DateTime?\n  scope                 String?\n  password              String?\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n\n  @@map(\"accounts\")\n}\n\nmodel Verification {\n  id         String   @id @default(cuid())\n  identifier String\n  value      String\n  expiresAt  DateTime\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@map(\"verifications\")\n}\n\n// ==============================================\n// Application Models\n// ==============================================\n\nmodel Category {\n  id                 String  @id @default(cuid())\n  name               String  @unique // \"የምስጋና መዝሙር\"\n  nameTransliterated String? // \"Praise Hymns\" (English equivalent)\n  description        String?\n  iconName           String? // Lucide icon name for sidebar UI\n\n  subCategories SubCategory[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"categories\")\n}\n\nmodel SubCategory {\n  id                 String  @id @default(cuid())\n  name               String // \"የቅድስት ሥላሴ\"\n  nameTransliterated String? // \"Holy Trinity\"\n  description        String?\n  iconName           String? // Lucide icon name\n\n  categoryId String\n  category   Category @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n\n  mezmurs Mezmur[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([name, categoryId])\n  @@map(\"sub_categories\")\n}\n\nmodel Zemari {\n  id          String  @id @default(cuid())\n  name        String  @unique // English or transliterated name\n  nameAmharic String? // Name in Amharic script\n  bio         String?\n  imageUrl    String?\n\n  mezmurs Mezmur[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"zemarian\")\n}\n\nenum YoutubeUrlSource {\n  AUTO_FETCHED\n  ADMIN_OVERRIDE\n}\n\nmodel Mezmur {\n  id      String   @id @default(cuid())\n  title   String // Amharic title — \"ዋይ ዜማ\"\n  lyrics  String[] // Postgres array — each element is one verse line\n  meaning String? // Optional Ge'ez-to-Amharic translation\n\n  // --- YouTube Cache Strategy ---\n  // null  = Cache MISS → triggers YouTube Data API v3 search\n  // value = Cache HIT  → serve instantly, skip API call\n  youtubeUrl       String?\n  youtubeUrlSource YoutubeUrlSource?\n\n  // --- Relationships ---\n  subCategoryId String\n  subCategory   SubCategory @relation(fields: [subCategoryId], references: [id])\n\n  zemariId String?\n  zemari   Zemari? @relation(fields: [zemariId], references: [id])\n\n  favorites     Favorite[]\n  ratings       Rating[]\n  listenHistory ListenHistory[]\n  userReports   UserReport[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([subCategoryId])\n  @@index([zemariId])\n  @@index([title])\n  @@map(\"mezmurs\")\n}\n\nmodel Favorite {\n  id       String @id @default(cuid())\n  userId   String\n  user     User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  mezmurId String\n  mezmur   Mezmur @relation(fields: [mezmurId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@unique([userId, mezmurId]) // One favorite per user per mezmur\n  @@map(\"favorites\")\n}\n\nmodel Rating {\n  id       String @id @default(cuid())\n  value    Int // 1–5 star rating\n  userId   String\n  user     User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  mezmurId String\n  mezmur   Mezmur @relation(fields: [mezmurId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([userId, mezmurId]) // One rating per user per mezmur\n  @@map(\"ratings\")\n}\n\nmodel ListenHistory {\n  id       String @id @default(cuid())\n  userId   String\n  user     User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  mezmurId String\n  mezmur   Mezmur @relation(fields: [mezmurId], references: [id], onDelete: Cascade)\n\n  playedAt DateTime @default(now()) // Updated on replay (upsert)\n\n  @@unique([userId, mezmurId]) // One entry per user per mezmur (upsert updates playedAt)\n  @@index([userId, playedAt(sort: Desc)]) // Fast query for \"recently played\"\n  @@map(\"listen_history\")\n}\n\n// ==============================================\n// Phase 5: Admin & Moderation\n// ==============================================\n\nmodel AuditLog {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(\"UserAuditLogs\", fields: [userId], references: [id])\n  action    String // e.g. \"UPDATE_MEZMUR\", \"ADD_URL\", \"DELETE_CATEGORY\"\n  targetId  String? // The ID of the affected resource (mezmurId, categoryId, etc.)\n  details   String? // Optional JSON string or extra info\n  createdAt DateTime @default(now())\n\n  @@map(\"audit_logs\")\n}\n\nmodel UserReport {\n  id        String   @id @default(cuid())\n  mezmurId  String\n  mezmur    Mezmur   @relation(fields: [mezmurId], references: [id], onDelete: Cascade)\n  issueType String // e.g. \"BROKEN_LINK\", \"TYPO\"\n  status    String   @default(\"PENDING\") // \"PENDING\", \"RESOLVED\", \"REJECTED\"\n  details   String? // Additional context from the user\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"user_reports\")\n}\n",
